export enum MediaType {
  VIDEO = 'VIDEO',
  IMAGE = 'IMAGE',
}

export interface ScriptSegment {
  id: string;
  originalText: string;
  notes: string[]; // Detected brackets or comments
  order: number;
}

export interface SearchQuery {
  mainQuery: string;
  variants: string[];
  keywords: string[];
}

export interface BrollSuggestion {
  segmentId: string;
  visualIntent: string; // What should be shown
  mediaType: MediaType;
  searchQuery: SearchQuery;
  styleParams: {
    mood: string;
    style: string; // e.g. "Cinematic", "Minimalist"
    negativePrompt?: string;
  };
  sources: {
    googleImages: string;
    pexels: string;
    unsplash: string;
    pinterest: string;
  };
  aiPrompt?: string; // If AI generation is suggested
}

export interface AnalysisResult {
  segment: ScriptSegment;
  suggestions: BrollSuggestion[];
}

export interface AppConfig {
  geminiKey: string;
  googleClientId: string;
  googleApiKey: string;
}

export interface ExportStats {
  totalSegments: number;
  coveredSegments: number;
  coveragePercent: number;
}

import mammoth from 'mammoth';
import { ScriptSegment } from '../types';

/**
 * Parses a .docx file buffer into structured script segments.
 * In a real-world scenario, this might be handled server-side for better performance with large files,
 * but mammoth.js works well in the browser for this use case.
 */
export const parseDocx = async (arrayBuffer: ArrayBuffer): Promise<ScriptSegment[]> => {
  try {
    const result = await mammoth.extractRawText({ arrayBuffer });
    const text = result.value;

    // Simple heuristic segmentation: Split by double newlines to find paragraphs.
    // In a production app, we would use XML parsing to find comments and footnotes specifically.
    // Here we simulate note extraction by looking for text inside [brackets] or {braces}.

    const rawSegments = text.split(/\n\s*\n/);
    const segments: ScriptSegment[] = [];

    let orderCounter = 0;

    rawSegments.forEach((raw) => {
      const trimmed = raw.trim();
      if (trimmed.length > 0) {
        // Extract notes (text in brackets)
        const noteRegex = /\[(.*?)\]|\{(.*?)\}/g;
        const notes: string[] = [];
        let match;
        while ((match = noteRegex.exec(trimmed)) !== null) {
          if (match[1]) notes.push(match[1]);
          if (match[2]) notes.push(match[2]);
        }

        // Clean text by removing notes for the main visual script
        const cleanText = trimmed.replace(noteRegex, '').trim();

        if (cleanText.length > 0 || notes.length > 0) {
          segments.push({
            id: `seg-${orderCounter}-${Date.now()}`,
            originalText: cleanText || "[Visual Note Only]",
            notes: notes,
            order: orderCounter++
          });
        }
      }
    });

    return segments;
  } catch (error) {
    console.error("Failed to parse DOCX", error);
    throw new Error("Failed to parse document. Please ensure it is a valid .docx file.");
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { ScriptSegment, BrollSuggestion, MediaType } from "../types";

const MODEL_NAME = "gemini-2.5-flash";

const SYSTEM_INSTRUCTION = `
You are an expert Video Editor and Creative Director. Your task is to analyze script segments and generate detailed B-Roll (supplementary footage) suggestions.

For each script segment provided:
1. Analyze the context, tone, and any embedded notes (instructions in brackets).
2. Suggest the BEST visual accompaniment (Video or Image).
3. Create a specific, optimized search query for stock footage sites.
4. Generate 3-8 relevant keywords.
5. Create alternative search variants (different angles, synonyms).
6. Define the visual style (Cinematic, Vlog, Corporate, etc.).
7. If the scene is abstract or hard to film, suggest a Generative AI prompt.

Return PURE JSON.
`;

export const generateBrollPlan = async (
  apiKey: string,
  segments: ScriptSegment[]
): Promise<BrollSuggestion[]> => {
  if (!apiKey) throw new Error("API Key is missing");

  const ai = new GoogleGenAI({ apiKey });

  // We process in batches to avoid huge payloads, but for this demo, we'll try a reasonable chunk.
  // In production: Queue system.

  const segmentsPayload = segments.map(s => ({
    id: s.id,
    text: s.originalText,
    notes: s.notes.join("; ")
  }));

  const prompt = `
    Analyze the following script segments and generate B-roll suggestions.

    Input Segments:
    ${JSON.stringify(segmentsPayload)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              segmentId: { type: Type.STRING },
              visualIntent: { type: Type.STRING, description: "Description of what is happening on screen" },
              mediaType: { type: Type.STRING, enum: ["VIDEO", "IMAGE"] },
              searchQuery: {
                type: Type.OBJECT,
                properties: {
                  mainQuery: { type: Type.STRING },
                  variants: { type: Type.ARRAY, items: { type: Type.STRING } },
                  keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
                }
              },
              styleParams: {
                type: Type.OBJECT,
                properties: {
                  mood: { type: Type.STRING },
                  style: { type: Type.STRING },
                  negativePrompt: { type: Type.STRING }
                }
              },
              aiPrompt: { type: Type.STRING, description: "Prompt for image generation models if needed" }
            }
          }
        }
      }
    });

    if (!response.text) {
      throw new Error("No response from Gemini");
    }

    const rawData = JSON.parse(response.text);

    // Post-process to add generated URLs
    return rawData.map((item: any) => {
      const queryEncoded = encodeURIComponent(item.searchQuery.mainQuery);
      return {
        ...item,
        sources: {
          googleImages: `https://www.google.com/search?tbm=isch&q=${queryEncoded}`,
          pexels: `https://www.pexels.com/search/${item.mediaType === 'VIDEO' ? 'videos/' : ''}${queryEncoded}`,
          unsplash: `https://unsplash.com/s/photos/${queryEncoded}`,
          pinterest: `https://www.pinterest.com/search/pins/?q=${queryEncoded}`
        }
      } as BrollSuggestion;
    });

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import { ScriptSegment, BrollSuggestion, ExportStats } from "../types";

/**
 * NOTE: This service uses the Google API Client Library (gapi) loaded in index.html.
 * It requires the user to provide a Client ID and API Key with scope 'https://www.googleapis.com/auth/documents'.
 */

// Helper to wait for GAPI
const waitForGapi = (): Promise<void> => {
  return new Promise((resolve) => {
    if (window.gapi && window.google) resolve();
    else {
      let interval = setInterval(() => {
        if (window.gapi && window.google) {
          clearInterval(interval);
          resolve();
        }
      }, 100);
    }
  });
};

export const initializeGoogleAuth = async (clientId: string, apiKey: string) => {
  await waitForGapi();
  return new Promise<void>((resolve, reject) => {
    window.gapi.load('client:auth2', async () => {
      try {
        await window.gapi.client.init({
          apiKey: apiKey,
          clientId: clientId,
          discoveryDocs: ["https://docs.googleapis.com/$discovery/rest?version=v1"],
          scope: "https://www.googleapis.com/auth/documents https://www.googleapis.com/auth/drive.file",
        });
        resolve();
      } catch (e) {
        reject(e);
      }
    });
  });
};

export const signInToGoogle = async (): Promise<boolean> => {
  const authInstance = window.gapi.auth2.getAuthInstance();
  if (!authInstance.isSignedIn.get()) {
    await authInstance.signIn();
  }
  return authInstance.isSignedIn.get();
};

export const createBrollDoc = async (
  filename: string,
  segments: ScriptSegment[],
  suggestions: BrollSuggestion[]
): Promise<{ docUrl: string; stats: ExportStats }> => {

  // 1. Create the Doc
  const createResponse = await window.gapi.client.docs.documents.create({
    title: filename,
  });
  const docId = createResponse.result.documentId;

  // 2. Build requests
  const requests: any[] = [];
  let index = 1; // Start index (1-based usually, but API is 0-based index)

  // Insert Title
  requests.push({
    insertText: {
      location: { index: 1 },
      text: `B-ROLL PLAN: ${filename}\n\n`
    }
  });
  requests.push({
    updateParagraphStyle: {
      range: { startIndex: 1, endIndex: 1 + `B-ROLL PLAN: ${filename}`.length },
      paragraphStyle: { namedStyleType: 'HEADING_1' },
      fields: 'namedStyleType'
    }
  });

  // Calculate current index roughly (gapi docs batch update handles offsets automatically if ordered backward, 
  // but to be safe usually we calculate. For simplicity here, we assume sequential append at end is tricky without tracking index.
  // Actually, easiest way is to insert text at the end using `endOfSegmentLocation` if available, or just track length.
  // Since we have to map exact indices, we will build the document in REVERSE order (bottom up) so indices don't shift 
  // OR calculate exact lengths. Let's do calculation.)

  // Actually, simpler strategy: Build a huge text string, insert it once, then apply styling. 
  // BUT we need hyperlinks. So we must use requests.

  // Let's iterate and build.
  // Note: For a robust app, we'd calculate exact indices. 
  // Here, for the demo, we'll try to insert at the end.
  // Google Docs API doesn't support "append" easily in batchUpdate without knowing the end index.
  // We will assume the document is empty and calculate.

  let currentIndex = 1 + `B-ROLL PLAN: ${filename}\n\n`.length;
  let coveredCount = 0;

  // We will construct requests to insert at the END.
  // But wait, inserting at 'end' means index is typically EOF-1.
  // To avoid index math hell, we will just format a text block and valid links.

  // Alternative: We generate the content, then make ONE insert call, then update styles/links.
  // It is hard to know indices after 1 insert.

  // Strategy: We will process segments in REVERSE order and always insert at index 1 (after title).
  // This pushes previous content down.
  // Wait, that reverses the document.

  // Let's stick to accumulating text and creating link ranges.
  let fullText = "";
  const linkRanges: { start: number; end: number; url: string }[] = [];
  const boldRanges: { start: number; end: number }[] = [];

  segments.forEach((seg) => {
    const sug = suggestions.find(s => s.segmentId === seg.id);
    const hasSug = !!sug;
    if (hasSug) coveredCount++;

    const header = `BLOCK ${seg.order + 1}\n`;
    const scriptText = `SCRIPT: "${seg.originalText.substring(0, 100)}${seg.originalText.length > 100 ? '...' : ''}"\n`;
    const notesText = seg.notes.length > 0 ? `NOTES: ${seg.notes.join(', ')}\n` : '';

    let brollText = "";
    if (sug) {
      brollText += `[${sug.mediaType}] Intent: ${sug.visualIntent}\n`;
      brollText += `Style: ${sug.styleParams.style} | Mood: ${sug.styleParams.mood}\n`;
      brollText += `SEARCH LINKS:\n`;
    } else {
      brollText += `NO B-ROLL SUGGESTED\n`;
    }

    const startOfBlock = currentIndex + fullText.length;

    // Append Header
    fullText += header;
    boldRanges.push({ start: startOfBlock, end: startOfBlock + header.length });

    fullText += scriptText;
    if (notesText) fullText += notesText;
    fullText += brollText;

    // Links
    if (sug) {
        const sources = [
            { name: "Google Images", url: sug.sources.googleImages },
            { name: "Pexels", url: sug.sources.pexels },
            { name: "Unsplash", url: sug.sources.unsplash },
            { name: "Pinterest", url: sug.sources.pinterest },
        ];

        sources.forEach(src => {
            const linkLabel = `🔗 ${src.name}\n`;
            const linkStart = currentIndex + fullText.length;
            fullText += linkLabel;
            linkRanges.push({ start: linkStart, end: linkStart + linkLabel.length - 1, url: src.url }); // -1 to skip newline
        });
    }

    fullText += "\n-------------------\n\n";
  });

  // Summary
  const summaryHeader = `SUMMARY\n`;
  fullText += summaryHeader;
  fullText += `Total Segments: ${segments.length}\n`;
  fullText += `Coverage: ${Math.round((coveredCount / segments.length) * 100)}%\n`;

  // Apply the Big Insert
  // Note: We need to account for the initial title length in our ranges.
  // currentIndex was set after title.

  // Adjust ranges relative to the insertion point (currentIndex)
  const adjustedRequests = [];

  // 1. Insert all text
  adjustedRequests.push({
    insertText: {
      location: { index: currentIndex },
      text: fullText
    }
  });

  // 2. Apply styles (Bold headers)
  boldRanges.forEach(r => {
      adjustedRequests.push({
          updateTextStyle: {
              range: { startIndex: currentIndex + (r.start - currentIndex), endIndex: currentIndex + (r.end - currentIndex) },
              textStyle: { bold: true },
              fields: 'bold'
          }
      });
  });

  // 3. Apply Links
  linkRanges.forEach(r => {
      adjustedRequests.push({
          updateTextStyle: {
              range: { startIndex: currentIndex + (r.start - currentIndex), endIndex: currentIndex + (r.end - currentIndex) },
              textStyle: { link: { url: r.url }, foregroundColor: { color: { rgbColor: { blue: 0.8, red: 0.1, green: 0.1 } } }, underline: true },
              fields: 'link,foregroundColor,underline'
          }
      });
  });

  await window.gapi.client.docs.documents.batchUpdate({
    documentId: docId,
    resource: { requests: adjustedRequests }
  });

  return {
    docUrl: `https://docs.google.com/document/d/${docId}/edit`,
    stats: {
        totalSegments: segments.length,
        coveredSegments: coveredCount,
        coveragePercent: Math.round((coveredCount / segments.length) * 100)
    }
  };
};

