            {/* Dashboard */}
            {segments.length > 0 && (
            <div className="space-y-8">
                {/* Toolbar */}
                <div className="flex flex-col sm:flex-row justify-between items-center gap-4 bg-white p-4 rounded-xl shadow-sm border border-slate-200">
