import { GoogleGenAI, Type } from "@google/genai";
import { ScriptSegment, BrollSuggestion, MediaType } from "../types";

const MODEL_NAME = "gemini-2.5-flash";

const SYSTEM_INSTRUCTION = `
You are a meticulous Video Editor and Creative Director. Your goal is to map a script to highly specific, relevant B-Roll.

PHASE 1: ANALYZE GLOBAL ATMOSPHERE & STYLE
Before generating suggestions, analyze the input segments to define a single, cohesive "Master Aesthetic" for this specific project.
- Determine the Mood (e.g., Dark/Gritty, Bright/Corporate, Minimalist/Clean, Cyberpunk/Neon).
- Determine the Visual Language (e.g., "Shot on 35mm film, grainy texture", "Hyper-realistic 8k, sharp focus", "Pastel color palette, soft lighting").

PHASE 2: GENERATE PROMPTS (Strict Rules)
1. **UNIFIED AESTHETIC:** Every single 'aiPrompt' you generate MUST include the "Master Aesthetic" description at the end. All images must look like they belong to the exact same movie or brand identity.
2. **ENTITY SPECIFICITY:**
   - If the script mentions a specific person (e.g., "Steve Jobs"), the prompt MUST name them.
   - If the script mentions a specific location (e.g., "The Louvre"), the prompt MUST name it.
   - If the script implies a specific object (e.g., "Ferrari F40"), do not say "red sports car".
3. **AI PROMPT STRUCTURE:**
   The 'aiPrompt' field string MUST be constructed exactly like this:
   "[Subject/Person defined in text] doing [Action defined in text] at [Location], [Camera Angle/Composition], [Master Aesthetic Description]"

For each script segment:
1. Identify specific nouns and entities.
2. Generate a Main Search Query for stock sites (Rigorous, Specific).
3. Generate an 'aiPrompt' following the structure defined above (Coherent, Stylized).
4. Return PURE JSON.
`;

export const generateBrollPlan = async (
  segments: ScriptSegment[],
  apiKey: string
): Promise<BrollSuggestion[]> => {
  // Use the key provided from the UI configuration
  const ai = new GoogleGenAI({ apiKey: apiKey });

  // Processing payload
  const segmentsPayload = segments.map(s => ({
    id: s.id,
    text: s.originalText,
    notes: s.notes.join("; ")
  }));

  const prompt = `
    Analyze the following script segments as a SINGLE COHESIVE VIDEO PROJECT. 
    First, determine the visual style that fits the narrative atmosphere. 
    Then, generate B-roll suggestions ensuring every AI prompt shares that exact same aesthetic style.

    Input Segments:
    ${JSON.stringify(segmentsPayload)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              segmentId: { type: Type.STRING },
              visualIntent: { type: Type.STRING, description: "Detailed description of the shot" },
              mediaType: { type: Type.STRING, enum: ["VIDEO", "IMAGE"] },
              searchQuery: {
                type: Type.OBJECT,
                properties: {
                  mainQuery: { type: Type.STRING, description: "The most specific search term possible" },
                  variants: { type: Type.ARRAY, items: { type: Type.STRING } },
                  keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
                },
                required: ["mainQuery", "keywords", "variants"]
              },
              styleParams: {
                type: Type.OBJECT,
                properties: {
                  mood: { type: Type.STRING },
                  style: { type: Type.STRING },
                  negativePrompt: { type: Type.STRING }
                },
                required: ["mood", "style"]
              },
              aiPrompt: { type: Type.STRING, description: "Highly detailed, consistent generative AI prompt" }
            },
            required: ["segmentId", "visualIntent", "mediaType", "searchQuery", "styleParams"]
          }
        }
      }
    });

    let jsonString = response.text;
    if (!jsonString) {
      throw new Error("No response from Gemini");
    }

    // Clean up markdown
    jsonString = jsonString.trim();
    if (jsonString.startsWith("```json")) {
        jsonString = jsonString.replace(/^```json/, "").replace(/```$/, "");
    } else if (jsonString.startsWith("```")) {
        jsonString = jsonString.replace(/^```/, "").replace(/```$/, "");
    }

    let rawData;
    try {
        rawData = JSON.parse(jsonString);
    } catch (e) {
        console.error("Failed to parse JSON", jsonString);
        throw new Error("Received malformed JSON from API");
    }

    return rawData.map((item: any) => {
      const searchQuery = item.searchQuery || {};
      const mainQuery = searchQuery.mainQuery || item.visualIntent || "stock footage";
      const queryEncoded = encodeURIComponent(mainQuery);

      const mediaType = item.mediaType === 'VIDEO' ? 'VIDEO' : 'IMAGE';

      return {
        ...item,
        mediaType,
        searchQuery: {
            mainQuery: mainQuery,
            variants: searchQuery.variants || [],
            keywords: searchQuery.keywords || []
        },
        styleParams: item.styleParams || { mood: "Neutral", style: "Standard" },
        sources: {
          googleImages: `https://www.google.com/search?tbm=isch&q=${queryEncoded}`,
          pexels: `https://www.pexels.com/search/${mediaType === 'VIDEO' ? 'videos/' : ''}${queryEncoded}`,
          unsplash: `https://unsplash.com/s/photos/${queryEncoded}`,
          pinterest: `https://www.pinterest.com/search/pins/?q=${queryEncoded}`
        }
      } as BrollSuggestion;
    });

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Upload, FileText, Settings, Loader2, PlayCircle, Download, AlertCircle, Plus } from 'lucide-react';
import SettingsModal from './components/SettingsModal';
import ScriptViewer from './components/ScriptViewer';
import Sidebar from './components/Sidebar';
import { parseDocx } from './services/docxService';
import { generateBrollPlan } from './services/geminiService';
import { downloadLocalFile } from './services/exportService';
import { saveSession, getHistory } from './services/historyService';
import { AppConfig, ScriptSegment, BrollSuggestion, UserProfile, HistorySession } from './types';

const INITIAL_CONFIG: AppConfig = {
  geminiKey: localStorage.getItem('br_geminiKey') || '',
};

// Hardcoded local user for history tracking
const LOCAL_USER: UserProfile = {
  email: 'local_user',
  name: 'Local User',
  picture: ''
};

function App() {
  // State
  const [config, setConfig] = useState<AppConfig>(INITIAL_CONFIG);
  const [history, setHistory] = useState<HistorySession[]>([]);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [suggestions, setSuggestions] = useState<BrollSuggestion[]>([]);
  const [currentFileName, setCurrentFileName] = useState<string>('');

  const [status, setStatus] = useState<'IDLE' | 'PARSING' | 'GENERATING' | 'EXPORTING'>('IDLE');
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem('br_geminiKey', config.geminiKey);
  }, [config]);

  // Load History on Mount
  useEffect(() => {
    const loadedHistory = getHistory(LOCAL_USER.email);
    setHistory(loadedHistory);
  }, []);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setStatus('PARSING');
    setError(null);
    setSegments([]);
    setSuggestions([]);
    setCurrentFileName(file.name.replace('.docx', ''));

    try {
      const arrayBuffer = await file.arrayBuffer();
      const parsedSegments = await parseDocx(arrayBuffer);

      if (parsedSegments.length === 0) {
        throw new Error("No readable text found in the document.");
      }

      setSegments(parsedSegments);
      setStatus('IDLE');
    } catch (err: any) {
      setError(err.message || "Failed to parse file");
      setStatus('IDLE');
    }
  };

  const handleGenerate = async () => {
    if (!config.geminiKey) {
        setIsSettingsOpen(true);
        setError("Please enter your Gemini API Key in settings.");
        return;
    }

    setStatus('GENERATING');
    setError(null);

    try {
      // Pass the key from state to the service
      const results = await generateBrollPlan(segments, config.geminiKey);
      setSuggestions(results);

      // Save to History
      saveSession(LOCAL_USER.email, currentFileName, segments, results);
      // Refresh history locally
      setHistory(getHistory(LOCAL_USER.email));

    } catch (err: any) {
      setError(err.message || "AI Generation failed");
    } finally {
      setStatus('IDLE');
    }
  };

  const handleDownload = () => {
    setStatus('EXPORTING');
    try {
      const docName = `B-Roll - ${currentFileName}`;
      downloadLocalFile(docName, segments, suggestions);
      // Small delay to show state change
      setTimeout(() => setStatus('IDLE'), 1000);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Download failed.");
      setStatus('IDLE');
    }
  };

  const handleSelectHistory = (session: HistorySession) => {
      setSegments(session.segments);
      setSuggestions(session.suggestions);
      setCurrentFileName(session.scriptName);
      setError(null);
  };

  const handleNewProject = () => {
    setSegments([]);
    setSuggestions([]);
    setCurrentFileName('');
    setStatus('IDLE');
    setError(null);
    if (fileInputRef.current) {
        fileInputRef.current.value = '';
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex">
      {/* Sidebar */}
      <Sidebar 
        user={LOCAL_USER} 
        history={history} 
        onSelectSession={handleSelectHistory}
      />

      <div className="flex-1 flex flex-col ml-64 transition-all">
        {/* Header */}
        <header className="bg-white border-b border-slate-200 sticky top-0 z-40">
            <div className="max-w-6xl mx-auto px-6 py-4 flex justify-between items-center">
            <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center text-white shadow-lg shadow-indigo-200">
                <PlayCircle className="w-6 h-6" />
                </div>
                <div>
                <h1 className="text-xl font-bold text-slate-900 tracking-tight">B-Roll Generator</h1>
                <p className="text-xs text-slate-500 font-medium">
                    {currentFileName ? `Project: ${currentFileName}` : "New Project"}
                </p>
                </div>
            </div>

            <div className="flex items-center gap-3">
                <button
                    onClick={handleNewProject}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors text-sm font-medium shadow-sm"
                >
                    <Plus className="w-4 h-4" />
                    New Project
                </button>
                <button
                    onClick={() => setIsSettingsOpen(true)}
                    className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors"
                    title="Settings"
                >
                    <Settings className="w-5 h-5" />
                </button>
            </div>
            </div>
        </header>

        {/* Main Content */}
        <main className="flex-1 max-w-6xl w-full mx-auto px-6 py-8">

            {/* Description Paragraph */}
            <div className="mb-8 text-center max-w-3xl mx-auto bg-indigo-50/50 p-6 rounded-2xl border border-indigo-100">
                <p className="text-slate-700 text-lg leading-relaxed font-medium">
                    Convierte tus guiones en planes visuales al instante. Sube tu archivo Word (.docx) y obtén sugerencias detalladas de imágenes y videos (B-Roll) que encajen perfectamente con tu historia, manteniendo un estilo visual único y coherente.
                </p>
            </div>

            {/* Error Banner */}
            {error && (
            <div className="mb-6 bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg flex items-center gap-3 animate-fade-in">
                <AlertCircle className="w-5 h-5 shrink-0" />
                {error}
            </div>
            )}

            {/* Empty State / Upload */}
            {segments.length === 0 && (
            <div className="mt-4 text-center p-12 border-2 border-dashed border-slate-300 rounded-2xl bg-white hover:bg-slate-50 transition-colors">
                <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-4">
                <Upload className="w-8 h-8" />
                </div>
                <h2 className="text-2xl font-bold text-slate-800 mb-2">Sube tu Guion</h2>
                <p className="text-slate-500 mb-8 max-w-md mx-auto">
                Selecciona un archivo .docx. Extraeremos el texto y generaremos sugerencias visuales rigurosas.
                </p>
                <input
                type="file"
                accept=".docx"
                ref={fileInputRef}
                onChange={handleFileUpload}
                className="hidden"
                />
                <button
                onClick={() => fileInputRef.current?.click()}
                className="px-8 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 font-medium shadow-lg shadow-indigo-200 transition-all transform hover:-translate-y-1"
                disabled={status === 'PARSING'}
                >
                {status === 'PARSING' ? <Loader2 className="w-5 h-5 animate-spin" /> : "Seleccionar Documento"}
                </button>
            </div>
            )}

            {/* Dashboard */}
            {segments.length > 0 && (
            <div className="space-y-8">
                {/* Toolbar */}
                <div className="flex flex-col sm:flex-row justify-between items-center gap-4 bg-white p-4 rounded-xl shadow-sm border border-slate-200">
                <div className="flex items-center gap-2 text-slate-600">
                    <FileText className="w-5 h-5" />
                    <span className="font-semibold">{segments.length} script segments found</span>
                </div>

                <div className="flex gap-3">
                    <button
                    onClick={handleGenerate}
                    disabled={status !== 'IDLE' || suggestions.length > 0}
                    className={`px-6 py-2.5 rounded-lg font-medium flex items-center gap-2 transition-colors ${
                        suggestions.length > 0 
                        ? 'bg-emerald-100 text-emerald-700 cursor-default' 
                        : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-md shadow-indigo-100'
                    }`}
                    >
                    {status === 'GENERATING' ? (
                        <><Loader2 className="w-4 h-4 animate-spin" /> Analyzing...</>
                    ) : suggestions.length > 0 ? (
                        "Visuals Generated"
                    ) : (
                        "Generate Visuals"
                    )}
                    </button>

                    {suggestions.length > 0 && (
                    <button
                        onClick={handleDownload}
                        disabled={status === 'EXPORTING'}
                        className="px-6 py-2.5 rounded-lg font-medium border border-slate-300 text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                    >
                        {status === 'EXPORTING' ? <Loader2 className="w-4 h-4 animate-spin" /> : <Download className="w-4 h-4" />}
                        Download (.md)
                    </button>
                    )}
                </div>
                </div>

                <ScriptViewer segments={segments} suggestions={suggestions} />
            </div>
            )}
        </main>

        <SettingsModal
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            config={config}
            onSave={(newConfig) => {
            setConfig(newConfig);
            setIsSettingsOpen(false);
            }}
        />
      </div>
    </div>
  );
}

export default App;

