import mammoth from 'mammoth';
import { ScriptSegment, ExtractedLink } from '../types';

/**
 * Parses a .docx file buffer into structured script segments.
 */
export const parseDocx = async (arrayBuffer: ArrayBuffer): Promise<ScriptSegment[]> => {
  try {
    const result = await mammoth.extractRawText({ arrayBuffer });
    const text = result.value;

    // Split logic: 
    // 1. Look for newlines (standard paragraphs) OR
    // 2. Look for sentence terminators (. ? !) followed by whitespace and a capital letter (start of new idea)
    // This regex creates a split on:
    // - Double newlines
    // - Single newlines
    // - Period/Question/Exclamation + Space + Lookahead for Uppercase or Start of sentence

    const splitRegex = /(?:\r?\n)+|(?<=[.!?])\s+(?=[A-Z¿¡])/;

    const rawSegments = text.split(splitRegex);
    const segments: ScriptSegment[] = [];

    let orderCounter = 0;

    // Regex for URLs
    const urlRegex = /(https?:\/\/[^\s]+)/g;

    rawSegments.forEach((raw) => {
      const trimmed = raw.trim();
      // Only keep segments that have actual content (more than just a symbol)
      if (trimmed.length > 2) {
        // Extract notes (text in brackets)
        const noteRegex = /\[(.*?)\]|\{(.*?)\}/g;
        const notes: string[] = [];
        let match;
        while ((match = noteRegex.exec(trimmed)) !== null) {
          if (match[1]) notes.push(match[1]);
          if (match[2]) notes.push(match[2]);
        }

        // Extract Links
        const extractedLinks: ExtractedLink[] = [];
        let linkMatch;
        while ((linkMatch = urlRegex.exec(trimmed)) !== null) {
          const url = linkMatch[0].replace(/[)]$/, ''); // Remove trailing parenthesis if caught
          let type: 'YOUTUBE' | 'IMAGE' | 'GENERIC' = 'GENERIC';

          if (url.includes('youtube.com') || url.includes('youtu.be')) {
            type = 'YOUTUBE';
          } else if (url.match(/\.(jpeg|jpg|gif|png|webp)$/i) || url.includes('imgur') || url.includes('drive.google.com')) {
            type = 'IMAGE';
          }

          extractedLinks.push({ url, type });
        }

        // Clean text by removing notes for the main visual script
        const cleanText = trimmed.replace(noteRegex, '').trim();

        if (cleanText.length > 0 || notes.length > 0) {
          segments.push({
            id: `seg-${orderCounter}-${Date.now()}`,
            originalText: cleanText || "[Visual Note Only]",
            notes: notes,
            extractedLinks: extractedLinks,
            order: orderCounter++
          });
        }
      }
    });

    return segments;
  } catch (error) {
    console.error("Failed to parse DOCX", error);
    throw new Error("Failed to parse document. Please ensure it is a valid .docx file.");
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { ScriptSegment, BrollSuggestion, MediaType } from "../types";

const MODEL_NAME = "gemini-2.5-flash";

export const generateBrollPlan = async (
  segments: ScriptSegment[],
  apiKey: string,
  userStyle: string = "Cinematic & High Quality",
  userTone: string = "Neutral"
): Promise<BrollSuggestion[]> => {
  const ai = new GoogleGenAI({ apiKey: apiKey });

  const SYSTEM_INSTRUCTION = `
    You are an Expert Cinematographer and AI Prompt Engineer (Midjourney/Runway/Sora expert). 
    Your goal is to map a script to specific B-Roll suggestions.

    **USER CONFIGURATION:**
    - **Visual Style:** ${userStyle}
    - **Narrative Tone:** ${userTone}

    **CRITICAL RULE FOR VIDEO PROMPTS:**
    If you choose 'VIDEO' as the media type, the 'aiPrompt' MUST be extremely detailed and technical. It is not enough to say "A man walking".
    You MUST describe:
    1. **Camera Movement:** (e.g., Slow dolly in, Truck left, Orbit, Static tripod, Handheld shake, Low angle tracking shot).
    2. **Framing:** (e.g., Extreme Close-Up of eyes, Wide shot, Over-the-shoulder).
    3. **Lighting:** (e.g., Volumetric lighting, Golden hour, Neon rim light, Soft diffused window light, High contrast noir).
    4. **Action/Transition:** Specific movement within the frame (e.g., "Smoke swirls slowly", "Character turns head to camera", "Fast blur transition").
    5. **Technical Specs:** (e.g., 4k, 60fps, shallow depth of field, bokeh, highly detailed, photorealistic).

    **CRITICAL RULE FOR SEGMENTATION:**
    The input segments are split by ideas/sentences. You must provide a visual for EVERY segment provided.

    **OUTPUT STRUCTURE (JSON):**
    For each segment:
    1. **Visual Intent:** A human-readable summary of the shot.
    2. **Media Type:** Choose VIDEO for action/emotion, IMAGE for specific objects/concepts.
    3. **Search Query:** A simplified keyword string for stock sites (Pexels/Unsplash).
    4. **AI Prompt:** The highly technical prompt described above.

    **AI PROMPT TEMPLATE (Use this pattern):**
    "[Subject] [Action] in [Environment]. [Camera Movement], [Framing], [Lighting]. Technical: [Specs]. Style: ${userStyle}, Mood: ${userTone}."
  `;

  // Processing payload
  const segmentsPayload = segments.map(s => ({
    id: s.id,
    text: s.originalText,
    notes: s.notes.join("; ")
  }));

  const prompt = `
    Analyze these script segments.
    Apply the visual style: "${userStyle}" and tone: "${userTone}".

    Input Segments:
    ${JSON.stringify(segmentsPayload)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              segmentId: { type: Type.STRING },
              visualIntent: { type: Type.STRING, description: "Detailed description of the shot" },
              mediaType: { type: Type.STRING, enum: ["VIDEO", "IMAGE"] },
              searchQuery: {
                type: Type.OBJECT,
                properties: {
                  mainQuery: { type: Type.STRING, description: "The most specific search term possible" },
                  variants: { type: Type.ARRAY, items: { type: Type.STRING } },
                  keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
                },
                required: ["mainQuery", "keywords", "variants"]
              },
              styleParams: {
                type: Type.OBJECT,
                properties: {
                  mood: { type: Type.STRING },
                  style: { type: Type.STRING },
                  negativePrompt: { type: Type.STRING }
                },
                required: ["mood", "style"]
              },
              aiPrompt: { type: Type.STRING, description: "Highly detailed, cinematic prompt with camera, lighting, and movement specs." }
            },
            required: ["segmentId", "visualIntent", "mediaType", "searchQuery", "styleParams"]
          }
        }
      }
    });

    let jsonString = response.text;
    if (!jsonString) {
      throw new Error("No response from Gemini");
    }

    // Clean up markdown
    jsonString = jsonString.trim();
    if (jsonString.startsWith("```json")) {
        jsonString = jsonString.replace(/^```json/, "").replace(/```$/, "");
    } else if (jsonString.startsWith("```")) {
        jsonString = jsonString.replace(/^```/, "").replace(/```$/, "");
    }

    let rawData;
    try {
        rawData = JSON.parse(jsonString);
    } catch (e) {
        console.error("Failed to parse JSON", jsonString);
        throw new Error("Received malformed JSON from API");
    }

    return rawData.map((item: any) => {
      const searchQuery = item.searchQuery || {};
      const mainQuery = searchQuery.mainQuery || item.visualIntent || "stock footage";
      const queryEncoded = encodeURIComponent(mainQuery);

      const mediaType = item.mediaType === 'VIDEO' ? 'VIDEO' : 'IMAGE';

      return {
        ...item,
        mediaType,
        searchQuery: {
            mainQuery: mainQuery,
            variants: searchQuery.variants || [],
            keywords: searchQuery.keywords || []
        },
        styleParams: item.styleParams || { mood: userTone, style: userStyle },
        sources: {
          googleImages: `https://www.google.com/search?tbm=isch&q=${queryEncoded}`,
          pexels: `https://www.pexels.com/search/${mediaType === 'VIDEO' ? 'videos/' : ''}${queryEncoded}`,
          unsplash: `https://unsplash.com/s/photos/${queryEncoded}`,
          pinterest: `https://www.pinterest.com/search/pins/?q=${queryEncoded}`
        }
      } as BrollSuggestion;
    });

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export enum MediaType {
  VIDEO = 'VIDEO',
  IMAGE = 'IMAGE',
}

export interface ExtractedLink {
  url: string;
  type: 'YOUTUBE' | 'IMAGE' | 'GENERIC';
}

export interface ScriptSegment {
  id: string;
  originalText: string;
  notes: string[]; // Detected brackets or comments
  extractedLinks: ExtractedLink[]; // New field for URLs found in text
  order: number;
}

export interface SearchQuery {
  mainQuery: string;
  youtubeQuery: string; // Specific query optimized for YouTube search
  variants: string[];
  keywords: string[];
}

export interface BrollSuggestion {
  segmentId: string;
  visualIntent: string; // What should be shown
  mediaType: MediaType;
  searchQuery: SearchQuery;
  styleParams: {
    mood: string;
    style: string; // e.g. "Cinematic", "Minimalist"
    negativePrompt?: string;
  };
  sources: {
    googleImages: string;
    pexels: string;
    unsplash: string;
    pinterest: string;
    youtube: string; // New source
  };
  aiPrompt?: string; // If AI generation is suggested
}

export interface AnalysisResult {
  segment: ScriptSegment;
  suggestions: BrollSuggestion[];
}

export interface AppConfig {
  geminiKey: string;
}

export interface ExportStats {
  totalSegments: number;
  coveredSegments: number;
  coveragePercent: number;
}

export interface UserProfile {
  email: string;
  name: string;
  picture: string;
}

export interface HistorySession {
  id: string;
  date: string; // ISO string
  scriptName: string;
  segments: ScriptSegment[];
  suggestions: BrollSuggestion[];
}

import React, { useState, useRef, useEffect } from 'react';
import { Upload, FileText, Settings, Loader2, PlayCircle, Download, AlertCircle, Plus, Menu, RotateCcw, Moon, Sun, Sliders } from 'lucide-react';
import SettingsModal from './components/SettingsModal';
import ScriptViewer from './components/ScriptViewer';
import Sidebar from './components/Sidebar';
import HowToGuide from './components/HowToGuide'; 
import { parseDocx } from './services/docxService';
import { generateBrollPlan } from './services/geminiService';
import { downloadLocalFile } from './services/exportService';
import { saveSession, getHistory, deleteSession } from './services/historyService';
import { AppConfig, ScriptSegment, BrollSuggestion, UserProfile, HistorySession } from './types';

const INITIAL_CONFIG: AppConfig = {
  geminiKey: localStorage.getItem('br_geminiKey') || '',
};

// Hardcoded local user for history tracking
const LOCAL_USER: UserProfile = {
  email: 'local_user',
  name: 'Local User',
  picture: ''
};

function App() {
  // Global State
  const [darkMode, setDarkMode] = useState(() => {
    return localStorage.getItem('theme') === 'dark';
  });

  // App State
  const [config, setConfig] = useState<AppConfig>(INITIAL_CONFIG);
  const [history, setHistory] = useState<HistorySession[]>([]);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false); 

  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [suggestions, setSuggestions] = useState<BrollSuggestion[]>([]);
  const [currentFileName, setCurrentFileName] = useState<string>('');

  // Advanced Generation Options
  // Default to Auto-Detect for better initial results
  const [userStyle, setUserStyle] = useState("Auto-Detect");
  const [userTone, setUserTone] = useState("Auto-Detect");

  const [status, setStatus] = useState<'IDLE' | 'PARSING' | 'GENERATING' | 'EXPORTING'>('IDLE');
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem('br_geminiKey', config.geminiKey);
  }, [config]);

  // Dark Mode Effect
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [darkMode]);

  // Load History on Mount
  useEffect(() => {
    const loadedHistory = getHistory(LOCAL_USER.email);
    setHistory(loadedHistory);
  }, []);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setStatus('PARSING');
    setError(null);
    setSegments([]);
    setSuggestions([]);
    setCurrentFileName(file.name.replace('.docx', ''));

    try {
      const arrayBuffer = await file.arrayBuffer();
      const parsedSegments = await parseDocx(arrayBuffer);

      if (parsedSegments.length === 0) {
        throw new Error("No se encontró texto legible en el documento.");
      }

      setSegments(parsedSegments);
      setStatus('IDLE');
    } catch (err: any) {
      setError(err.message || "Error al leer el archivo");
      setStatus('IDLE');
    }
  };

  const handleGenerate = async () => {
    if (!config.geminiKey) {
        setIsSettingsOpen(true);
        setError("Por favor configura tu API Key de Gemini en los ajustes.");
        return;
    }

    setStatus('GENERATING');
    setError(null);

    try {
      // Pass the key AND the new style/tone options
      const results = await generateBrollPlan(segments, config.geminiKey, userStyle, userTone);
      setSuggestions(results);

      // Save to History
      saveSession(LOCAL_USER.email, currentFileName, segments, results);
      // Refresh history locally
      setHistory(getHistory(LOCAL_USER.email));

    } catch (err: any) {
      setError(err.message || "Falló la generación con IA");
    } finally {
      setStatus('IDLE');
    }
  };

  const handleRegenerate = () => {
      // Clears current suggestions to trigger re-run
      setSuggestions([]); 
      handleGenerate();
  };

  const handleDeleteSession = (sessionId: string) => {
    const updatedHistory = deleteSession(LOCAL_USER.email, sessionId);
    setHistory(updatedHistory);
    // If the currently viewed session is deleted, clear the view
    // Note: We don't strictly have a 'currentSessionId' state, but we check if segments match.
    // Simpler approach: Just keep current view, but next refresh it's gone from history.
  };

  const handleDownload = () => {
    setStatus('EXPORTING');
    try {
      const docName = `B-Roll - ${currentFileName}`;
      downloadLocalFile(docName, segments, suggestions);
      setTimeout(() => setStatus('IDLE'), 1000);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Error en descarga.");
      setStatus('IDLE');
    }
  };

  const handleSelectHistory = (session: HistorySession) => {
      setSegments(session.segments);
      setSuggestions(session.suggestions);
      setCurrentFileName(session.scriptName);
      setError(null);
      setIsMobileMenuOpen(false); 
  };

  const handleNewProject = () => {
    setSegments([]);
    setSuggestions([]);
    setCurrentFileName('');
    setStatus('IDLE');
    setError(null);
    // Reset options to default
    setUserStyle("Auto-Detect");
    setUserTone("Auto-Detect");
    if (fileInputRef.current) {
        fileInputRef.current.value = '';
    }
    setIsMobileMenuOpen(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-900 transition-colors flex flex-col md:flex-row">
      {/* Sidebar - Responsive */}
      <Sidebar 
        user={LOCAL_USER} 
        history={history} 
        onSelectSession={handleSelectHistory}
        onDeleteSession={handleDeleteSession}
        isOpen={isMobileMenuOpen}
        onClose={() => setIsMobileMenuOpen(false)}
      />

      {/* Main Container */}
      <div className="flex-1 flex flex-col md:ml-64 transition-all w-full">

        {/* Header */}
        <header className="bg-white dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800 sticky top-0 z-30 transition-colors">
            <div className="max-w-6xl mx-auto px-4 md:px-6 py-3 md:py-4 flex justify-between items-center">

            <div className="flex items-center gap-3">
                {/* Mobile Menu Button */}
                <button 
                    onClick={() => setIsMobileMenuOpen(true)}
                    className="md:hidden p-2 -ml-2 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg"
                >
                    <Menu className="w-6 h-6" />
                </button>

                <div className="w-9 h-9 md:w-10 md:h-10 bg-indigo-600 rounded-lg flex items-center justify-center text-white shadow-lg shadow-indigo-200 dark:shadow-none shrink-0">
                    <PlayCircle className="w-5 h-5 md:w-6 md:h-6" />
                </div>
                <div className="overflow-hidden">
                    <h1 className="text-lg md:text-xl font-bold text-slate-900 dark:text-white tracking-tight truncate">Generador B-Roll</h1>
                    <p className="text-[10px] md:text-xs text-slate-500 dark:text-slate-400 font-medium truncate max-w-[150px] md:max-w-none">
                        {currentFileName ? currentFileName : "Nuevo Proyecto"}
                    </p>
                </div>
            </div>

            <div className="flex items-center gap-2 md:gap-3">
                 {/* Dark Mode Toggle */}
                 <button
                    onClick={() => setDarkMode(!darkMode)}
                    className="p-2 text-slate-400 hover:text-indigo-500 dark:hover:text-yellow-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
                >
                    {darkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
                </button>

                <button
                    onClick={handleNewProject}
                    className="flex items-center gap-2 px-3 py-2 md:px-4 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors text-xs md:text-sm font-medium shadow-sm"
                >
                    <Plus className="w-4 h-4" />
                    <span className="hidden md:inline">Nuevo</span>
                    <span className="md:hidden">Nuevo</span>
                </button>
                <button
                    onClick={() => setIsSettingsOpen(true)}
                    className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
                    title="Configuración"
                >
                    <Settings className="w-5 h-5" />
                </button>
            </div>
            </div>
        </header>

        {/* Main Content Area */}
        <main className="flex-1 max-w-6xl w-full mx-auto px-4 md:px-6 py-6 md:py-8">

            {/* Description Paragraph (Only visible on empty state) */}
            {segments.length === 0 && (
                <div className="mb-8 text-center max-w-3xl mx-auto bg-indigo-50/50 dark:bg-indigo-900/20 p-6 rounded-2xl border border-indigo-100 dark:border-indigo-900">
                    <p className="text-slate-700 dark:text-slate-300 text-base md:text-lg leading-relaxed font-medium">
                        Convierte tus guiones en planes visuales al instante. Sube tu archivo Word (.docx) y obtén sugerencias detalladas de imágenes y videos (B-Roll) que encajen perfectamente con tu historia.
                    </p>
                </div>
            )}

            {/* Error Banner */}
            {error && (
            <div className="mb-6 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-300 px-4 py-3 rounded-lg flex items-center gap-3 animate-fade-in text-sm md:text-base">
                <AlertCircle className="w-5 h-5 shrink-0" />
                {error}
            </div>
            )}

            {/* Empty State / Upload */}
            {segments.length === 0 && (
            <>
                <div className="mt-4 text-center p-8 md:p-12 border-2 border-dashed border-slate-300 dark:border-slate-700 rounded-2xl bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                    <div className="w-14 h-14 md:w-16 md:h-16 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-full flex items-center justify-center mx-auto mb-4">
                        <Upload className="w-7 h-7 md:w-8 md:h-8" />
                    </div>
                    <h2 className="text-xl md:text-2xl font-bold text-slate-800 dark:text-white mb-2">Sube tu Guion</h2>
                    <p className="text-slate-500 dark:text-slate-400 mb-6 md:mb-8 max-w-md mx-auto text-sm md:text-base">
                        Selecciona un archivo .docx. Extraeremos el texto y generaremos sugerencias visuales rigurosas.
                    </p>
                    <input
                        type="file"
                        accept=".docx"
                        ref={fileInputRef}
                        onChange={handleFileUpload}
                        className="hidden"
                    />
                    <button
                        onClick={() => fileInputRef.current?.click()}
                        className="w-full md:w-auto px-8 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 font-medium shadow-lg shadow-indigo-200 dark:shadow-none transition-all transform hover:-translate-y-1 active:scale-95"
                        disabled={status === 'PARSING'}
                    >
                        {status === 'PARSING' ? <div className="flex items-center justify-center gap-2"><Loader2 className="w-5 h-5 animate-spin" /> Leyendo...</div> : "Seleccionar Documento"}
                    </button>
                </div>

                {/* How to Guide (Rendered below upload box) */}
                <HowToGuide />
            </>
            )}

            {/* Dashboard */}
            {segments.length > 0 && (
            <div className="space-y-6 md:space-y-8">

                {/* Toolbar & Advanced Options */}
                <div className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 sticky top-20 z-20 space-y-4 md:space-y-0">

                    {/* Top Row: Info + Action Buttons */}
                    <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                        <div className="flex items-center gap-2 text-slate-600 dark:text-slate-300 text-sm md:text-base">
                            <FileText className="w-4 h-4 md:w-5 md:h-5" />
                            <span className="font-semibold">{segments.length} bloques encontrados</span>
                        </div>

                        <div className="flex flex-col sm:flex-row gap-3 w-full sm:w-auto">

                            {/* Regenerate Button (Only if visuals exist) */}
                            {suggestions.length > 0 && (
                                <button 
                                    onClick={handleRegenerate}
                                    disabled={status !== 'IDLE'}
                                    className="px-4 py-2.5 rounded-lg font-medium border border-indigo-200 dark:border-indigo-800 text-indigo-700 dark:text-indigo-300 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 flex items-center justify-center gap-2 text-sm md:text-base transition-colors"
                                    title="Volver a generar con nuevos ajustes"
                                >
                                    <RotateCcw className="w-4 h-4" />
                                    <span className="hidden md:inline">Regenerar</span>
                                </button>
                            )}

                            <button
                                onClick={handleGenerate}
                                disabled={status !== 'IDLE' || suggestions.length > 0}
                                className={`w-full sm:w-auto px-4 md:px-6 py-2.5 rounded-lg font-medium flex justify-center items-center gap-2 transition-colors text-sm md:text-base ${
                                    suggestions.length > 0 
                                    ? 'bg-emerald-100 dark:bg-emerald-900/50 text-emerald-700 dark:text-emerald-300 cursor-default' 
                                    : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-md shadow-indigo-100 dark:shadow-none'
                                }`}
                            >
                            {status === 'GENERATING' ? (
                                <><Loader2 className="w-4 h-4 animate-spin" /> Analizando...</>
                            ) : suggestions.length > 0 ? (
                                "Visuales Generados"
                            ) : (
                                "Generar Visuales"
                            )}
                            </button>

                            {suggestions.length > 0 && (
                            <button
                                onClick={handleDownload}
                                disabled={status === 'EXPORTING'}
                                className="w-full sm:w-auto px-4 md:px-6 py-2.5 rounded-lg font-medium border border-slate-300 dark:border-slate-600 text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex justify-center items-center gap-2 text-sm md:text-base"
                            >
                                {status === 'EXPORTING' ? <Loader2 className="w-4 h-4 animate-spin" /> : <Download className="w-4 h-4" />}
                                Descargar (.md)
                            </button>
                            )}
                        </div>
                    </div>

                    {/* Advanced Options Row (Visible when not generated yet, or when user wants to see settings) */}
                    {suggestions.length === 0 && (
                        <div className="pt-4 border-t border-slate-100 dark:border-slate-700 grid grid-cols-1 md:grid-cols-2 gap-4 animate-fade-in">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase mb-1 flex items-center gap-1">
                                    <Sliders className="w-3 h-3" /> Estilo Visual
                                </label>
                                <select 
                                    value={userStyle}
                                    onChange={(e) => setUserStyle(e.target.value)}
                                    className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg p-2 text-sm text-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                                >
                                    <option value="Auto-Detect">✨ Auto-Detect (IA Decision)</option>
                                    <option value="Cinematic & High Quality">Cinematográfico (Default)</option>
                                    <option value="Documentary & Raw">Documental / Realista</option>
                                    <option value="Minimalist & Clean">Minimalista / Corporativo</option>
                                    <option value="Cyberpunk & Neon">Cyberpunk / Futurista</option>
                                    <option value="Vintage & Grainy">Vintage / Retro</option>
                                    <option value="Bright & Commercial">Comercial / Publicidad TV</option>
                                    <option value="Dark & Moody">Oscuro / Dramático</option>
                                </select>
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase mb-1">
                                    Tono Narrativo
                                </label>
                                <select 
                                    value={userTone}
                                    onChange={(e) => setUserTone(e.target.value)}
                                    className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg p-2 text-sm text-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                                >
                                    <option value="Auto-Detect">✨ Auto-Detect (IA Decision)</option>
                                    <option value="Neutral">Neutral (Informativo)</option>
                                    <option value="Emotional & Touching">Emocional / Conmovedor</option>
                                    <option value="Energetic & Fast">Energético / Rápido</option>
                                    <option value="Professional & Serious">Profesional / Serio</option>
                                    <option value="Funny & Lighthearted">Divertido / Ligero</option>
                                    <option value="Suspenseful">Misterioso / Suspenso</option>
                                </select>
                            </div>
                            <div className="md:col-span-2 text-[10px] text-slate-400 dark:text-slate-500 italic text-center">
                                Nota: Los bloques se definen por las frases e ideas de tu documento.
                            </div>
                        </div>
                    )}
                </div>

                <ScriptViewer segments={segments} suggestions={suggestions} />
            </div>
            )}
        </main>

        <SettingsModal
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            config={config}
            onSave={(newConfig) => {
            setConfig(newConfig);
            setIsSettingsOpen(false);
            }}
        />
      </div>
    </div>
  );
}

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { ScriptSegment, BrollSuggestion, MediaType } from "../types";

const MODEL_NAME = "gemini-2.5-flash";

export const generateBrollPlan = async (
  segments: ScriptSegment[],
  apiKey: string,
  userStyle: string = "Auto-Detect",
  userTone: string = "Auto-Detect"
): Promise<BrollSuggestion[]> => {
  const ai = new GoogleGenAI({ apiKey: apiKey });

  // If Auto-Detect is selected, we instruction the model to perform analysis first.
  const isAutoStyle = userStyle === "Auto-Detect";
  const isAutoTone = userTone === "Auto-Detect";

  const SYSTEM_INSTRUCTION = `
    You are an Elite Visual Director for high-end documentary and commercial video production. 
    You are NOT a basic stock searcher. You are a CONTEXTUAL RESEARCHER.

    **GLOBAL OBJECTIVE:**
    Analyze the ENTIRE SCRIPT to understand the specific subject matter (e.g., "The History of Bitcoin", "Climate Change in 2024", "A specific Wedding").

    **STRICTNESS RULES (CRITICAL):**
    1. **NO GENERIC METAPHORS:** If the script says "It changed everything" in the context of Bitcoin, DO NOT suggest a "man looking at sunrise". Suggest "Bitcoin price chart skyrocketing on a monitor".
    2. **SUBJECT CONSISTENCY:** Every single visual suggestion MUST contain the main subject of the script. If the script is about dogs, do not show a generic "happy family" unless a dog is present.
    3. **CONTEXT IS KING:** Look at the surrounding segments. If Segment 1 mentions "1980s", Segment 2 must visually reflect the 1980s even if the text doesn't explicitly say "1980s".

    **USER CONFIGURATION:**
    - **Visual Style:** ${isAutoStyle ? "YOU MUST DECIDE THE BEST STYLE based on the script content." : userStyle}
    - **Narrative Tone:** ${isAutoTone ? "YOU MUST DECIDE THE BEST TONE based on the script content." : userTone}

    **YOUTUBE SEARCH LOGIC:**
    - You must generate a specific 'youtubeQuery'.
    - YouTube queries are different from Stock queries.
    - Stock: "Bitcoin golden coin on table"
    - YouTube: "Bitcoin history documentary footage 2009", "Satoshi Nakamoto explained clip", "News anchor talking about Bitcoin crash".
    - Use terms like: "documentary clip", "archival footage", "interview", "news report", "scene", "gameplay" (if gaming).

    **VIDEO PROMPT ENGINEERING (HOLLYWOOD STANDARD):**
    - If Media Type is VIDEO, the 'aiPrompt' must be production-ready.
    - Include: Camera Movement (Dolly, Pan, Truck), Lens (35mm, Anamorphic), Lighting (Rembrandt, Neon, Natural), and Action.
    - Example: "Close-up of a vintage computer monitor displaying green code. Slow dolly in. Dusty room, shaft of sunlight hitting the screen. 4k, cinematic."

    **OUTPUT STRUCTURE (JSON):**
    Return a valid JSON array where each object corresponds to a segment.
  `;

  // Processing payload
  const segmentsPayload = segments.map(s => ({
    id: s.id,
    text: s.originalText,
    notes: s.notes.join("; ")
  }));

  const prompt = `
    Analyze these script segments.
    ${isAutoStyle ? "Determine the best visual style yourself." : `Apply style: ${userStyle}`}
    ${isAutoTone ? "Determine the best tone yourself." : `Apply tone: ${userTone}`}

    Input Segments:
    ${JSON.stringify(segmentsPayload)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              segmentId: { type: Type.STRING },
              visualIntent: { type: Type.STRING, description: "Detailed description of the specific shot relating to the script context" },
              mediaType: { type: Type.STRING, enum: ["VIDEO", "IMAGE"] },
              searchQuery: {
                type: Type.OBJECT,
                properties: {
                  mainQuery: { type: Type.STRING, description: "Stock site optimized query (subject + action)" },
                  youtubeQuery: { type: Type.STRING, description: "YouTube optimized query (topic + 'footage'/'clip'/'documentary')" },
                  variants: { type: Type.ARRAY, items: { type: Type.STRING } },
                  keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
                },
                required: ["mainQuery", "youtubeQuery", "keywords", "variants"]
              },
              styleParams: {
                type: Type.OBJECT,
                properties: {
                  mood: { type: Type.STRING },
                  style: { type: Type.STRING },
                  negativePrompt: { type: Type.STRING }
                },
                required: ["mood", "style"]
              },
              aiPrompt: { type: Type.STRING, description: "Extremely detailed technical prompt for GenAI video" }
            },
            required: ["segmentId", "visualIntent", "mediaType", "searchQuery", "styleParams"]
          }
        }
      }
    });

    let jsonString = response.text;
    if (!jsonString) {
      throw new Error("No response from Gemini");
    }

    // Clean up markdown
    jsonString = jsonString.trim();
    if (jsonString.startsWith("```json")) {
        jsonString = jsonString.replace(/^```json/, "").replace(/```$/, "");
    } else if (jsonString.startsWith("```")) {
        jsonString = jsonString.replace(/^```/, "").replace(/```$/, "");
    }

    let rawData;
    try {
        rawData = JSON.parse(jsonString);
    } catch (e) {
        console.error("Failed to parse JSON", jsonString);
        throw new Error("Received malformed JSON from API");
    }

    return rawData.map((item: any) => {
      const searchQuery = item.searchQuery || {};
      const mainQuery = searchQuery.mainQuery || item.visualIntent || "stock footage";
      const youtubeQuery = searchQuery.youtubeQuery || mainQuery + " footage";

      const queryEncoded = encodeURIComponent(mainQuery);
      const ytQueryEncoded = encodeURIComponent(youtubeQuery);

      const mediaType = item.mediaType === 'VIDEO' ? 'VIDEO' : 'IMAGE';

      return {
        ...item,
        mediaType,
        searchQuery: {
            mainQuery: mainQuery,
            youtubeQuery: youtubeQuery,
            variants: searchQuery.variants || [],
            keywords: searchQuery.keywords || []
        },
        styleParams: item.styleParams || { mood: userTone, style: userStyle },
        sources: {
          googleImages: `https://www.google.com/search?tbm=isch&q=${queryEncoded}`,
